CREATE DATABASE dataset_for_graph; USE dataset_for_graph; 
CREATE TABLE store_sales (ss_sold_date_sk INT(8), ss_sold_time_sk INT(8), ss_item_sk INT(8), ss_customer_sk INT(8), ss_cdemo_sk INT(8), ss_hdemo_sk INT(8), ss_addr_sk INT(8), ss_store_sk INT(8), ss_promo_sk INT(8), ss_ticket_number INT(8), ss_quantity INT(8), ss_wholesale_cost DECIMAL(7, 2), ss_list_price DECIMAL(7, 2), ss_sales_price DECIMAL(7, 2), ss_ext_discount_amt DECIMAL(7, 2), ss_ext_sales_price DECIMAL(7, 2), ss_ext_wholesale_cost DECIMAL(7, 2), ss_ext_list_price DECIMAL(7, 2), ss_ext_tax DECIMAL(7, 2), ss_coupon_amt DECIMAL(7, 2), ss_net_paid DECIMAL(7, 2), ss_net_paid_inc_tax DECIMAL(7, 2), ss_net_profit DECIMAL(7, 2)); 
CREATE TABLE customer (c_customer_sk INT(8), c_customer_id CHAR(255), c_current_cdemo_sk INT(8), c_current_hdemo_sk INT(8), c_current_addr_sk INT(8), c_first_shipto_date_sk INT(8), c_first_sales_date_sk INT(8), c_salutation CHAR(255), c_first_name CHAR(255), c_last_name CHAR(255), c_preferred_cust_flag CHAR(255), c_birth_day INT(8), c_birth_month INT(8), c_birth_year INT(8), c_birth_country CHAR(255), c_login CHAR(255), c_email_address CHAR(255), c_last_review_date_sk INT(4)); 
CREATE TABLE date_dim (d_date_sk INT(8), d_date_id CHAR(255), d_date DATE, d_month_seq INT(8), d_week_seq INT(8), d_quarter_seq INT(8), d_year INT(8), d_dow INT(8), d_moy INT(8), d_dom INT(8), d_qoy INT(8), d_fy_year INT(8), d_fy_quarter_seq INT(8), d_fy_week_seq INT(8), d_day_name CHAR(255), d_quarter_name CHAR(255), d_holiday CHAR(255), d_weekend CHAR(255), d_following_holiday CHAR(255), d_first_dom INT(8), d_last_dom INT(8), d_same_day_ly INT(8), d_same_day_lq INT(8), d_current_day CHAR(255), d_current_week CHAR(255), d_current_month CHAR(255), d_current_quarter CHAR(255), d_current_year CHAR(255)); 
CREATE TABLE item (i_item_sk INT(8), i_item_id CHAR(255), i_rec_start_date DATE, i_rec_end_date DATE, i_item_desc CHAR(255), i_current_price DECIMAL(7, 2), i_wholesale_cost DECIMAL(7, 2), i_brand_id INT(8), i_brand CHAR(255), i_class_id INT(8), i_class CHAR(255), i_category_id INT(8), i_category CHAR(255), i_manufact_id INT(8), i_manufact CHAR(255), i_size CHAR(255), i_formulation CHAR(255), i_color CHAR(255), i_units CHAR(255), i_container CHAR(255), i_manager_id INT(8), i_product_name CHAR(255)); 
SELECT * FROM store_sales ss, customer c, date_dim d, item i WHERE ss.ss_customer_sk = c.c_customer_sk AND ss.ss_sold_date_sk = d.d_date_sk AND ss.ss_item_sk = i.i_item_sk;
